113	// installFromExtractedDir is the shared core install routine used by the
114	// Remote, Dir, and FS entrypoints. It assumes the package contents are
115	// already present on disk at sourceDir.
116	func installFromExtractedDir(pkg *Package, sourceDir, projectRoot string, entry InstalledEntry) (InstalledEntry, error) {
117		// Switch into projectRoot so relative install targets resolve against the
118		// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
119		// the recorded entry.Files paths project-relative.
120		if projectRoot != "" {
121			absProject, absErr := filepath.Abs(projectRoot)
122			if absErr == nil {
123				if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
124					if err := os.Chdir(absProject); err == nil {
125						defer func() { _ = os.Chdir(origDir) }()
126					}
127				}
128			}
129		}
130	
131		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
132			if manifestPkg != nil {
133				pkg = manifestPkg
134			}
135		} else {
136			if len(manifestIssues) > 0 {
137				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
138			}
139			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
140		}
141	
142		if pkg.Install.Root == nil {
143			pkg.Install.Root = &InstallMapping{
144				Source: ".",
145				Target: defaultPackageRootTarget(pkg.Name),
146			}
147		}
148	
149		// FEAT-015: plugin install targets must be project-relative. Manifests
150		// that try to write into the user's home are rejected so plugins can't
151		// pollute global state.
152		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
153			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
154		}
155	
156		if issues := ValidatePackageStructure(sourceDir, pkg); len(issues) > 0 {
157			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
158		}
159	
160		// Process Root mapping — copy the plugin tree into the project-local
161		// install location (e.g. .ddx/plugins/<name>/).
162		var installedRoot string
163		files, err := copyMapping(sourceDir, pkg.Install.Root)
164		if err != nil {
165			return entry, fmt.Errorf("installing plugin root: %w", err)
166		}
167		entry.Files = append(entry.Files, files...)
168		installedRoot = ExpandHome(pkg.Install.Root.Target)
169	
170		// Ensure declared executables have the execute bit set.
171		for _, rel := range pkg.Install.Executable {
172			p := filepath.Join(installedRoot, filepath.FromSlash(rel))
173			if info, err := os.Stat(p); err == nil && !info.IsDir() {
174				_ = os.Chmod(p, info.Mode()|0111)
175			}
176		}
177	
178		// Process Skills via the manifest mappings. Each mapping copies real files
179		// into its declared target. No symlinks are ever created -- this is the
180		// cross-platform invariant that FEAT-015 relies on.
181		if len(pkg.Install.Skills) > 0 {
182			written, err := installMappings(sourceDir, pkg.Install.Skills)
183			if err != nil {
184				return entry, fmt.Errorf("installing skills: %w", err)
185			}
186			entry.Files = append(entry.Files, written...)
187		}
188	
189		// Process Scripts mapping — copy the script to the target path.
190		// If the target is already a symlink, the developer is managing it
191		// themselves (e.g. symlink to their git checkout) — skip with a notice.
192		if pkg.Install.Scripts != nil {
193			dst := ExpandHome(pkg.Install.Scripts.Target)
194			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
195				target, _ := os.Readlink(dst)
196				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
197				entry.Files = append(entry.Files, dst)
198			} else {
199				srcDir := sourceDir
200				if installedRoot != "" {
201					srcDir = installedRoot
202				}
203				files, err := copyMapping(srcDir, pkg.Install.Scripts)
204				if err != nil {
205					return entry, fmt.Errorf("installing scripts: %w", err)
206				}
207				entry.Files = append(entry.Files, files...)
208	
209				// Ensure the installed script is executable.
210				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
211					_ = os.Chmod(dst, info.Mode()|0111)
212				}
213			}
214		}
215	
216		// Process symlinks.
217		for _, sym := range pkg.Install.Symlinks {
218			src := ExpandHome(sym.Source)
219			dst := ExpandHome(sym.Target)
220	
221			// Create parent dir if needed.
222			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
223				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
224			}
225	
226			// Remove existing symlink/file if present.
227			if _, err := os.Lstat(dst); err == nil {
228				if err := os.RemoveAll(dst); err != nil {
229					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
230				}
231			}
232	
233			if err := os.Symlink(src, dst); err != nil {
234				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
235			}
236			entry.Files = append(entry.Files, dst)
237		}
238	
239		return entry, nil
240	}
