274	// installMappings applies each mapping relative to srcDir and returns the
275	// project-relative files written by those mappings.
276	func installMappings(srcDir string, mappings []InstallMapping) ([]string, error) {
277		var written []string
278		for _, mapping := range mappings {
279			files, err := copyMapping(srcDir, &mapping)
280			if err != nil {
281				return nil, fmt.Errorf("copy %q -> %q: %w", mapping.Source, mapping.Target, err)
