288	// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
289	// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
290	func InstallResource(resourcePath string) (InstalledEntry, error) {
291		entry := InstalledEntry{
292			Name:        resourcePath,
293			Version:     "latest",
294			Type:        PackageTypeResource,
295			Source:      "https://github.com/DocumentDrivenDX/ddx-library",
296			InstalledAt: time.Now(),
297		}
298	
299		// resourcePath is like "persona/strict-code-reviewer"
300		parts := strings.SplitN(resourcePath, "/", 2)
301		if len(parts) != 2 {
302			return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
303		}
304		resourceType, resourceName := parts[0], parts[1]
305	
306		// Determine target directory relative to cwd.
307		target := filepath.Join(".ddx", "plugins", "ddx", resourceType+"s")
308		if err := os.MkdirAll(target, 0755); err != nil {
309			return entry, fmt.Errorf("creating target directory %s: %w", target, err)
310		}
311	
312		// Fetch raw file from GitHub.
313		rawURL := fmt.Sprintf(
314			"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
315			resourceType, resourceName,
316		)
317	
318		destFile := filepath.Join(target, resourceName+".md")
319		if err := downloadFile(rawURL, destFile); err != nil {
320			return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
321		}
322	
323		entry.Files = append(entry.Files, destFile)
324		return entry, nil
325	}
